import numpy as np

def dpo_loss(pi_w_logratio, pi_l_logratio, beta=0.1):
    diff = beta * (pi_w_logratio - pi_l_logratio)
    return -np.log(1.0 / (1.0 + np.exp(-diff)))

def run_practice():
    loss = dpo_loss(0.0, 0.0, 0.1)
    assert np.allclose(loss, 0.693147)
    print('[PASS] DPO loss calculations verified.')

if __name__ == '__main__':
    run_practice()
